sql:
SELECT state_id, MAX(sample_size) AS max_sample_size
FROM survey_states
GROUP BY state_id;

SELECT income_id, COUNT(response_id) AS total_responses
FROM survey_responses_by_income
GROUP BY income_id;

SELECT education_id, COUNT(*) as response_count
FROM survey_responses_by_education
GROUP BY education_id;

SELECT survey_id, state_id, response_rate
FROM survey_states
WHERE response_rate = (SELECT MAX(response_rate) FROM survey_states);

